            &lt;span style="color: #fff; font-size: 1.1em; font-weight: 500;"&gt;${d.Tarefa}&lt;/span&gt;
          &lt;/div&gt;
          &lt;div style="display: flex; flex-direction: column; align-items: flex-end; gap: 6px;"&gt;
            &lt;span style="background: ${corBorda}; color: ${txtBorda}; padding: 3px 10px; border-radius: 12px; font-size: 0.7em; font-weight: bold; text-transform: uppercase;"&gt;
